dataSource.select:
SELECT a.VALUE FROM PEN_DEC_FACT_TYPES_INSTANCE a WHERE
a.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND a.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND a.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND a.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND a.INS_INSURED_ID = :P_INSURED_ID AND
a.TITLE_CODE = '00075' AND a.DEC_FACT_TYPE_CODE = '00116';

SELECT TO_DATE(a.VALUE,'DD/MM/RRRR') FROM PEN_DEC_FACT_TYPES_INSTANCE a WHERE
a.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND a.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND a.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND a.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND a.INS_INSURED_ID = :P_INSURED_ID AND
a.TITLE_CODE = '00075' AND a.DEC_FACT_TYPE_CODE = '00112';

SELECT TO_DATE(a.VALUE,'DD/MM/RRRR') FROM PEN_DEC_FACT_TYPES_INSTANCE a WHERE
a.DI_DEC_INCR_SEQ_NO_SR = :P_DEC_INCR_SEC_NO_SR AND a.DI_DECISION_YEAR_SR = :P_DT_DECISION_YEAR_SR AND a.DI_DEC_UNIT_CODE_SR = :P_DT_DEC_UNIT_CODE_SR AND a.DI_DOCUMENT_TYPE_DEC_COCE_SR = '1' AND a.INS_INSURED_ID = :P_INSURED_ID AND
a.TITLE_CODE = '00075' AND a.DEC_FACT_TYPE_CODE = '00114';

function.textSource:
      function CF_1Formula return VARCHAR2 is
  V_DISPLAY CHAR(13);
begin
  
IF :branch_domain_type='10' THEN
	V_DISPLAY:='Περιφερειακού ';
end if;
IF :branch_domain_type='11' THEN
	V_DISPLAY:='Τοπικού ';
end if;

return v_display;

end;

      function CF_SEXFormula return Char is

V_DISPLAY CHAR(16);

begin
  
IF :SEX='Α' THEN
	V_DISPLAY:='του ασφαλισμένου';
end if;
IF :SEX='θ' THEN
	V_DISPLAY:='της ασφαλισμένης';
end if;

return v_display;
end;

      function CF_2Formula return Number is
begin
	
	IF NVl(:CS_4,0) = 0 OR NVL(:CS_1,0) = 0 THEN
	  RETURN(NVL(:P_SALARY,0));
	ELSE  	
    RETURN(NVl(:CS_4,0) + NVL(:CS_2,0) + NVL(:CS_1,0));
	END IF;
	
end;

      function F_32FormatTrigger return boolean is
begin
  
  return (TRUE);
end;

      function F_10FormatTrigger return boolean is
begin
  
  return (NVl(:CS_4,0) != 0 AND NVl(:CS_2,0) !=0 AND NVL(:CS_1,0) != 0);
end;

      function F_12FormatTrigger return boolean is
begin
  
  return (NVL(:CS_4,0) = 0 AND NVL(:CS_2,0) = 0 AND NVL(:CS_1,0) = 0);
end;

      function B_39FormatTrigger return boolean is
PAGE_NUM  NUMBER;
begin
 srw.get_page_num (page_num);
  if  page_num <> 1 then
   return(false);
end if;
  return (TRUE);
  
end;

      function CF_3Formula return Number is
begin
  RETURN(:CS_5 + :CS_8);
end;

      function CF_4Formula return Number is
begin
  RETURN(:CS_6 + :CS_9);
end;

      function CF_5Formula return Number is
begin
  RETURN(:CS_7 + :CS_10);
end;

      function CF_6Formula return Number is
begin
  RETURN(:CS_12 + :CS_11);
end;
